local GUILotteryReplaceContent = class("GUILotteryReplaceContent", IGUILayout)

function GUILotteryReplaceContent:onLoad()
    self.llOld = self:getChildWindow("LotteryReplaceContent-old", GUIType.Layout)
    self.llNew = self:getChildWindow("LotteryReplaceContent-new", GUIType.Layout)

    self.tvPriceText = self:getChildWindow("LotteryReplaceContent-tip", GUIType.StaticText)

    self.tvPriceText:SetText(Lang:getString("lottery_reward_replace"))

    self.oldItem = GUILotteryDetailItem.new("BedWarLotteryDetailItem.json")
    self.newItem = GUILotteryDetailItem.new("BedWarLotteryDetailItem.json")

    self.llOld:AddChildWindow(self.oldItem.root)
    self.llNew:AddChildWindow(self.newItem.root)
end

LotteryReplaceContent = buildCustomDialogContent(GUILotteryReplaceContent, "LotteryReplaceContent.json")

function LotteryReplaceContent:setGoodsInfo(oldItemId, newItemId)
    self.oldItem:onDataChanged(LotteryConfig.findRewardByRewardId(oldItemId))
    self.newItem:onDataChanged(LotteryConfig.findRewardByRewardId(newItemId))
end
